function isEmpty(source) {
    // Checks for null, undefined, not an array, or empty array
    return !Array.isArray(source) || source.length === 0;
}

logger.error("Source role: " + JSON.stringify(source));
if(!isEmpty(source)){
var sourceRoleId = source[0]._refResourceId;
logger.error("sourceRoleId ref: "+sourceRoleId);

try {

    var roleResponse = openidm.query(
        "managed/alpha_role",{
             "_queryFilter": '_id eq "' + sourceRoleId + '"'
        },
        ["businessRoleId"]
    );
    logger.error("Role Response: " + JSON.stringify(roleResponse));

    if (roleResponse.result && roleResponse.result.length == 1) {

		var roleId = roleResponse.result[0].businessRoleId;
		logger.error("roleId in response : "+roleId);

    } else {
		logger.error("Exception occurred during role to policy link " );
    }
} catch (e) {
    logger.error("Exception occurred: " + e);  
}
roleId;
}else{
	null;
}

function isEmpty(source) {
    // Checks for null, undefined, not an array, or empty array
    return !Array.isArray(source) || source.length === 0;
}

logger.error("Source prerequisite: " + JSON.stringify(source));
if(!isEmpty(source)){
var resultArray = [];
logger.error("prerequisite length : "+source.length);
for(var i = 0; i < source.length; i++){
	var sourcePrereqId = source[i]._refResourceId;
	logger.error("sourcePrereqId ref: "+sourcePrereqId);

	try {

		var prereqResponse = openidm.query(
			"managed/alpha_kyid_enrollment_prerequisite",{
				 "_queryFilter": '_id eq "' + sourcePrereqId + '"'
			},
			["name"]
		);
		logger.error("Prerequisite Response: " + JSON.stringify(prereqResponse));

		if (prereqResponse.result && prereqResponse.result.length == 1) {

			var prereqName = prereqResponse.result[0].name;
			logger.error("prereqName in response : "+prereqName);
			resultArray.push(prereqName);

		} else {
			logger.error("Exception occurred during prereq to policy link " );
		}
	} catch (e) {
		logger.error("Exception occurred: " + e);  
	}
	//prereqId;
}
var resultString = resultArray.join('|');
logger.error("Result Array as | separated string: " + resultString);
resultString;
}else{
	null;
}

